        $response = $this->actingAs($user)->post("/autofix/{$dataset->id}");

        $response->assertRedirect();

        $row->refresh();
        $dataset->refresh();

        $this->assertSame('active', $row->payload['status']);
        $this->assertSame(0, (int) data_get($dataset->metrics, 'open_issues', 0));
